patches.new_code:
// 1. I'm -> im 처럼 아포스트로피는 병합하여 제거하고, gonna -> going to 등 구어체 동의어를 통일하는 전처리 함수
const normalizeText = (t) => {
    let text = t.toLowerCase();
    text = text.replace(/['‘’`]/g, ''); // 아포스트로피는 공백 없이 제거 (I'm -> im, don't -> dont)
    text = text.replace(/[.,!?"”“\-]/g, ' '); // 나머지 기호는 공백으로 변경하여 단어 분리

    // STT가 다르게 인식하기 쉬운 구어체/축약어 동의어 사전
    const slangMap = {
        "gonna": "going to", "wanna": "want to", "gotta": "got to",
        "lemme": "let me", "gimme": "give me", "kinda": "kind of",
        "sorta": "sort of", "outta": "out of", "cuz": "because", "cause": "because"
    };
    return text.split(/\s+/).map(w => slangMap[w] || w).join(' ').trim();
};

const originalClean = normalizeText(original);
const spokenClean = normalizeText(spoken);

const originalWords = originalClean.split(/\s+/).filter(Boolean);
const spokenWords = spokenClean.split(/\s+/).filter(Boolean);
